part of '../app_router.dart';

PassengerDriverSnapshotInfo? _toPassengerDriverSnapshotInfo(
  PassengerDriverSnapshotUi? snapshot,
) {
  if (snapshot == null) {
    return null;
  }
  return PassengerDriverSnapshotInfo(
    name: snapshot.name,
    plate: snapshot.plate,
    phone: snapshot.phone,
  );
}

PassengerDriverSnapshotInfo? _toPassengerDriverSnapshotFromTripData(
  Map<String, dynamic>? tripData,
) {
  final rawSnapshot = tripData?['driverSnapshot'];
  if (rawSnapshot is! Map) {
    return null;
  }

  final snapshotMap = <String, dynamic>{};
  for (final entry in rawSnapshot.entries) {
    snapshotMap[entry.key.toString()] = entry.value;
  }

  final name = _nullableToken(snapshotMap['name'] as String?);
  final plate = _nullableToken(snapshotMap['plate'] as String?);
  final phone = _nullableToken(snapshotMap['phone'] as String?);
  if (name == null && plate == null && phone == null) {
    return null;
  }

  return PassengerDriverSnapshotInfo(
    name: name ??
