PassengerDriverSnapshotInfo? _toPassengerDriverSnapshotFromDriverData(
  Map<String, dynamic>? driverData,
) {
  if (driverData == null) {
    return null;
  }

  final name = _nullableToken(driverData['name'] as String?);
  final plate = _nullableToken(driverData['plate'] as String?);
  final showPhoneToPassengers = driverData['showPhoneToPassengers'] == true;
  final phone = showPhoneToPassengers
      ? _nullableToken(driverData['phone'] as String?)
      : null;

  if (name == null && plate == null && phone == null) {
    return null;
  }

