List<PassengerStopInfo> _resolvePassengerStops(
  QuerySnapshot<Map<String, dynamic>>? snapshot,
) {
  if (snapshot == null || snapshot.docs.isEmpty) {
    return const <PassengerStopInfo>[];
  }

  final stops = <PassengerStopInfo>[];
  for (final doc in snapshot.docs) {
    final data = doc.data();
    final nameRaw = (data['name'] as String?)?.trim();
    final name = (nameRaw == null || nameRaw.isEmpty) ? 'Durak' : nameRaw;
    final isPassed = data['isPassed'] == true;
    final isNext = data['isNext'] == true;
    final waitingRaw = data['passengersWaiting'];
    final passengersWaiting = waitingRaw is num ? waitingRaw.toInt() : null;
    stops.add(
      PassengerStopInfo(
        name: name,
        isPassed: isPassed,
        isNext: isNext,
        passengersWaiting: passengersWaiting,
      ),
    );
  }
  return stops;
}
